import type { OidcIssuerAdapter } from "@cyspbot/oidc/issuer-adapter";
import type { TrustedOidcIssuer } from "@cyspbot/oidc";

const googleAccountsIssuer = "https://accounts.google.com";
const googleAccountsJwksUri = new URL("https://www.googleapis.com/oauth2/v3/certs");

export const googleServiceAccountTrustedIssuer = {
  allowedSigningAlgorithms: ["RS256"],
  issuer: googleAccountsIssuer,
  jwksUri: googleAccountsJwksUri,
} satisfies TrustedOidcIssuer;

export const googleServiceAccountIssuerAdapter = {
  canHandleIssuer: (issuer) => issuer === googleServiceAccountTrustedIssuer.issuer,
  trustedIssuers: [googleServiceAccountTrustedIssuer],
  validateSubjectTokenBinding: ({ claims }) =>
    typeof claims["azp"] === "string" &&
    claims["azp"].length > 0 &&
    typeof claims.sub === "string" &&
    claims.sub.length > 0 &&
    typeof claims.exp === "number" &&
    claims["azp"] === claims.sub,
} satisfies OidcIssuerAdapter;
