import { describe, expect, it } from "vitest";

import {
  googleServiceAccountIssuerAdapter,
  googleServiceAccountTrustedIssuer,
} from "../src/issuer.ts";

describe("Google service-account OIDC issuer adapter", () => {
  it("exposes the configured Google service-account trusted issuer", () => {
    expect(googleServiceAccountIssuerAdapter).toMatchObject({
      trustedIssuers: [googleServiceAccountTrustedIssuer],
    });
    expect(
      googleServiceAccountIssuerAdapter.canHandleIssuer(googleServiceAccountTrustedIssuer.issuer),
    ).toBe(true);
  });

  it("accepts service-account ID token bindings", () => {
    expect(
      googleServiceAccountIssuerAdapter.validateSubjectTokenBinding({
        claims: {
          azp: "107517467455664443765",
          exp: 1,
          sub: "107517467455664443765",
        },
        expectedAudience: "cyspbot",
        subjectTokenType: "id_token",
      }),
    ).toBe(true);
  });

  it("rejects missing and mismatched authorized parties", () => {
    expect(
      googleServiceAccountIssuerAdapter.validateSubjectTokenBinding({
        claims: {
          exp: 1,
          sub: "107517467455664443765",
        },
        expectedAudience: "cyspbot",
        subjectTokenType: "id_token",
      }),
    ).toBe(false);
    expect(
      googleServiceAccountIssuerAdapter.validateSubjectTokenBinding({
        claims: {
          azp: "different-service-account-id",
          exp: 1,
          sub: "107517467455664443765",
        },
        expectedAudience: "cyspbot",
        subjectTokenType: "id_token",
      }),
    ).toBe(false);
  });
});
